122	func isFullCommitSHA(commitSHA string) bool {
123		if len(commitSHA) != 40 {
124			return false
125		}
126		for i := 0; i < len(commitSHA); i++ {
127			c := commitSHA[i]
128			if c >= '0' && c <= '9' {
129				continue
130			}
131			if c >= 'a' && c <= 'f' {
132				continue
133			}
134			if c >= 'A' && c <= 'F' {
135				continue
136			}
137			return false
138		}
139		return true
140	}
